// Created: 2026-06-25

/**
 * Real-filesystem E2E test for the activation analytics writer.
 *
 * Every other analytics test mocks `node:fs` or `appendAnalytics`, and the
 * dispatcher e2e tests rely on `isTestEnv()` (VITEST set) short-circuiting
 * `appendAnalytics` to a no-op. That means NO test actually exercised the
 * real write path to disk — which is the path that silently froze
 * agent-usage.jsonl for ~78 days (orphaned dispatcher, #2653).
 *
 * This test closes that structural gap: it bypasses the test-env guard,
 * points HOME at a throwaway temp dir, calls the REAL `appendAnalytics`, forces
 * a synchronous buffer flush, then reads the file back off disk and asserts the
 * line is well-formed JSONL with the expected activation-record shape.
 *
 * Only the HTTP sink is mocked, so the test stays hermetic (no network) while
 * the local file-write path under test remains fully real.
 */

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { mkdtempSync, rmSync, readFileSync, existsSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

// Keep the test hermetic: neutralize the best-effort HTTP sink so no network
// call is attempted regardless of the developer's environment. The local
// JSONL write path (the thing under test) stays real.
vi.mock('../../lib/telemetry-http-sink.js', () => ({
  postAnalyticsToSink: vi.fn(),
}));

import { appendAnalytics } from '../../lib/analytics.js';
import { flush, _resetForTesting } from '../../lib/analytics-buffer.js';

describe('appendAnalytics — real filesystem write path', () => {
  let tmpHome: string;
  let savedHome: string | undefined;
  let savedVitest: string | undefined;
  let savedJest: string | undefined;

  beforeEach(() => {
    _resetForTesting();
    tmpHome = mkdtempSync(join(tmpdir(), 'ork-analytics-realfs-'));

    // Redirect getHomeDir() → temp dir (getHomeDir reads process.env.HOME first).
    savedHome = process.env.HOME;
    process.env.HOME = tmpHome;

    // Bypass isTestEnv() so the real write actually happens. Restored in afterEach.
    savedVitest = process.env.VITEST;
    savedJest = process.env.JEST_WORKER_ID;
    delete process.env.VITEST;
    delete process.env.JEST_WORKER_ID;
  });

  afterEach(() => {
    // Restore env first — before any other test observes a missing VITEST.
    if (savedVitest === undefined) delete process.env.VITEST;
    else process.env.VITEST = savedVitest;
    if (savedJest === undefined) delete process.env.JEST_WORKER_ID;
    else process.env.JEST_WORKER_ID = savedJest;
    if (savedHome === undefined) delete process.env.HOME;
    else process.env.HOME = savedHome;

    _resetForTesting();
    rmSync(tmpHome, { recursive: true, force: true });
  });

  it('writes a well-formed JSONL line to ~/.claude/analytics/agent-usage.jsonl', () => {
    // Mirror the exact record the SubagentStop dispatcher emits (unified-dispatcher.ts).
    const record = {
      ts: '2026-06-25T06:44:05.152Z',
      pid: '582b46ee369e',
      agent: 'Explore',
      agent_name: null,
      model: 'claude-opus-4-8',
      duration_ms: 1234,
      success: true,
      output_len: 0,
      last_msg_len: 7640,
    };

    appendAnalytics('agent-usage.jsonl', record);
    flush(); // buffered writer normally flushes on process exit; force it here

    const filePath = join(tmpHome, '.claude', 'analytics', 'agent-usage.jsonl');
    expect(existsSync(filePath), 'agent-usage.jsonl should exist on disk').toBe(true);

    const contents = readFileSync(filePath, 'utf8');
    const lines = contents.trim().split('\n').filter(Boolean);
    expect(lines).toHaveLength(1);

    const parsed = JSON.parse(lines[0]) as Record<string, unknown>;
    expect(parsed).toMatchObject(record);
    // Trailing newline contract: each entry is one line terminated by \n.
    expect(contents.endsWith('\n')).toBe(true);
  });

  it('appends (does not truncate) across multiple activations', () => {
    appendAnalytics('agent-usage.jsonl', { agent: 'Explore', success: true });
    appendAnalytics('agent-usage.jsonl', { agent: 'Plan', success: false });
    flush();

    const filePath = join(tmpHome, '.claude', 'analytics', 'agent-usage.jsonl');
    const lines = readFileSync(filePath, 'utf8').trim().split('\n').filter(Boolean);
    expect(lines).toHaveLength(2);
    expect((JSON.parse(lines[0]) as { agent: string }).agent).toBe('Explore');
    expect((JSON.parse(lines[1]) as { agent: string }).agent).toBe('Plan');
  });

  it('stays a no-op under isTestEnv() (guards against accidental writes in CI)', () => {
    // Re-assert the guard: with VITEST set, nothing should hit disk.
    process.env.VITEST = 'true';
    appendAnalytics('agent-usage.jsonl', { agent: 'ShouldNotWrite', success: true });
    flush();

    const filePath = join(tmpHome, '.claude', 'analytics', 'agent-usage.jsonl');
    expect(existsSync(filePath)).toBe(false);
  });
});
